import React from 'react';
import { motion } from 'framer-motion';
import { Settings as SettingsIcon, Bell, Shield, LogOut, ChevronRight } from 'lucide-react';

export default function Settings() {
  return (
    <div className="max-w-2xl mx-auto space-y-8">
      <div>
        <h2 className="text-3xl font-black text-slate-900 flex items-center gap-3">
          <SettingsIcon className="text-teal-600" /> Account Settings
        </h2>
        <p className="text-slate-500 font-medium ml-9">Manage your privacy and security preferences.</p>
      </div>

      <div className="bg-white rounded-[40px] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-4 space-y-2">
          <SettingItem icon={<Bell />} label="Push Notifications" description="Receive alerts for new barter requests." toggle={true} />
          <SettingItem icon={<Shield />} label="Public Profile" description="Allow others to see your skills and rating." toggle={true} />
          <SettingItem icon={<Shield />} label="Two-Factor Auth" description="Extra security for token transactions." toggle={false} />
        </div>
        
        <div className="bg-slate-50 p-6 flex flex-col gap-4">
          <button className="w-full bg-white text-red-500 border border-red-100 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-red-50 transition-all">
            <LogOut size={18} /> Log Out from All Devices
          </button>
          <p className="text-center text-[10px] text-slate-400 font-black uppercase tracking-widest">Wertech v0.1.0-beta</p>
        </div>
      </div>
    </div>
  );
}

function SettingItem({ icon, label, description, toggle }) {
  return (
    <div className="flex items-center justify-between p-6 hover:bg-slate-50 rounded-[32px] transition-all cursor-pointer group">
      <div className="flex items-center gap-4">
        <div className="text-slate-400 group-hover:text-teal-600 transition-colors">{icon}</div>
        <div>
          <h4 className="font-bold text-slate-900">{label}</h4>
          <p className="text-xs text-slate-400">{description}</p>
        </div>
      </div>
      {toggle ? (
        <div className="w-12 h-6 bg-teal-500 rounded-full relative shadow-inner">
          <div className="absolute right-1 top-1 w-4 h-4 bg-white rounded-full shadow-sm" />
        </div>
      ) : <ChevronRight className="text-slate-300" />}
    </div>
  );
}
